package com.yottastudios.ns.collabspace.grpc;

import com.baomidou.mybatisplus.core.metadata.IPage;
import com.yottastudios.ns.collabspace.auth.vo.CreateNotifyVo;
import com.yottastudios.ns.collabspace.auth.vo.LoginValidateVo;
import com.yottastudios.ns.collabspace.organization.vo.UnitMemberVo;
import com.yottastudios.ns.collabspace.space.dto.SpaceAcrossConfigDto;
import com.yottastudios.ns.collabspace.space.vo.ApitableSpaceVo;
import com.yottastudios.ns.collabspace.space.vo.SpaceMemberNumVo;
import com.yottastudios.ns.collabspace.space.vo.SpaceMemberVo;
import com.yottastudios.ns.collabspace.space.vo.TeamMemberVo;
import com.yottastudios.ns.collabspace.team.dto.TeamInfoDto;
import com.yottastudios.ns.collabspace.user.excel.model.ExportMemberWithTeamData;
import com.yottastudios.ns.collabspace.user.vo.AppTeamSimpleInfoVo;
import com.yottastudios.ns.collabspace.user.vo.UserSimpleInfoVo;
import com.yottastudios.ns.collabspace.workspace.ro.SpaceNodeRelRo;
import com.yottastudios.ns.collabspace.workspace.vo.NodeRoleUnit;
import com.yottastudios.ns.collabspace.workspace.dto.NodeShareProps;
import com.yottastudios.ns.collabspace.workspace.vo.ExportLuckysheetResult;

import java.util.List;
import java.util.Map;

/**
 * Apitable grpc client interface
 */
public interface IApitableGrpcClientService {
    UserSimpleInfoVo getUserByEmail(String email);

    UserSimpleInfoVo getUserById(Long userId);

    UserSimpleInfoVo getUserByName(String name);

    Long selectUserIdByApiKey(String apiKey);

    Long register(String username, String nickname, Boolean isMmSync);

    String createSpace(Long userId, String spaceName);

    Boolean renameSpace(Long userId, String spaceId, String newSpaceName);

    List<ApitableSpaceVo> listSpaces(Long userId);

    void emailInvitation(Long inviteUserId, String spaceId, List<String> emails);

    String createNode(Long userId, String spaceId, String name, Integer type, SpaceNodeRelRo extra);

    Long getRootTeamUnitId(String spaceId);

    List<UnitMemberVo> findUnitMemberVo(List<Long> userIds, String spaceId);

    List<NodeRoleUnit> getNodeRoleUnitList(String spaceId, List<Long> unitIds);

    List<Long> getUnitsByMember(Long userId, String spaceId);

    String importNode(Long userId, String spaceId, String fileName, String fileSuffix, String url);

    String importLuckysheetNode(Long userId, String spaceId, String fileName, String fileSuffix, String url);

    void deleteNode(Long userId, String spaceId, String nodeId);

    void recoverNode(Long userId, String spaceId, String nodeId);

    void deleteNodeTotally(Long userId, String spaceId, String nodeId);

    List<UserSimpleInfoVo> getUserByIds(List<Long> userIds);

    List<UserSimpleInfoVo> getUserByEmails(List<String> emails);

    List<Long> emailInvitationRelTeam(Long inviteUserId, String spaceId, List<Long> teamIds, List<String> emails);

    void removeFromSpaceByEmail(String spaceId, Long userId, String email);

    List<TeamInfoDto> selectTeamByIdsIgnoreDelete(List<Long> teamIds);


    List<UserSimpleInfoVo> getAllValidUsers(Long userId);

    List<UserSimpleInfoVo> getAllExistUsers(Long userId);

    List<UserSimpleInfoVo> getUsersLikeNickname(String nickname);

    List<UserSimpleInfoVo> getExistUsersByNicknameLike(String nickname);

    void departUserByEmail(String email, Boolean isMmSync,Long opUserId);

    void departUsersInEmails(List<String> emails, Boolean isMmSync);

    void recoverUserByEmail(String email, Boolean isMmSync);

    void recoverUsersInEmails(List<String> emails, Boolean isMmSync);

    void updateIsMmSyncSourceByUserIds(List<Long> userIds, Boolean isMmSync);

    List<TeamInfoDto> selectTeamsBySpaceIds(List<String> spaceIds);

    /**
     * teamId为0L时, 邀请到根team
     */
    void addUsersToTeam(String spaceId, List<Long> userIds, Long teamId, Boolean bindTag);

    void removeUsersFromTeam(String spaceId, List<Long> userIds, Long teamId,Long operatorId, Boolean bindTag);

    void updateMemberBindTag(List<Long> teamIds);

    List<AppTeamSimpleInfoVo> queryOrCreateTeams(String spaceId, List<String> teamNames, Long appTeamParentId);

    List<UserSimpleInfoVo> selectMembersByTeamId(String spaceId, Long teamId);

    void deleteTeamByTeamId(Long appTeamId,boolean aioBind);

    void nodeInfoSync(String nodeId, String spaceId, Long userId, String nodeName);

    void addSpaceSubAdmin(String spaceId, List<Long> userIds, List<String> resourceCodes);

    String copyNodeToSpace(Long userId, String destSpaceId, String destParentId, String sourceNodeId, Boolean notCopyOutlineDoc);

    String exportNodeToSpaceCopy(String spaceId, List<String> nodeIds);

    String exportNodeToSpaceCopyFromMirror(String spaceId, List<String> nodeIds);

    /**
     * @param downloadUrl 从其他服务器导出的内容的下载链接
     * @param migrateHost 迁移附件用的host, 一般填其它服务器用的minio的url
     */
    void importNodeToSpaceCopy(String downloadUrl, String migrateHost);

    void updateShareScope(String nodeId, List<String> viewIds, Boolean isAll);

    String saveOrUpdateShareByShareId(String shareId, List<String> viewIds, NodeShareProps props, String nodeId, Boolean isAll, Long userId, String defaultViewId);

    LoginValidateVo validateLogin(String username, String password);

    ExportLuckysheetResult exportLuckysheetToMinio(String nodeId);

    CreateNotifyVo createNotify(List<String> userIds, String nodeId, String shareNodeId, Boolean isKnockNotify, String spaceId, String nodeName);

    CreateNotifyVo createExternalNotify(List<String> toUserIds, String spaceId,
                                        String templateId, String fromUserId, String notifyBody,
                                        String nodeId, String sourceSystem);

    List<SpaceMemberNumVo> getSpaceMemberNum(List<String> spaceIdList);

    IPage<SpaceMemberVo> getSpaceMembers(String spaceId, Integer pageNumber, Integer pageSize);

    Boolean replaceManagerBySuper(Long userId, String spaceId, Long OpUserId, String email);

    List<TeamMemberVo> getTeamMembers(String spaceId, Long userId);

    String copyFile(Long userId, String targetSpaceId, String nodeId);

    Boolean updateUserNickBatch(List<ExportMemberWithTeamData> updateUserNikeList);

    Boolean recoverUserStatus(List<String> emailList);

    Boolean changeAppTeamName(String spaceId, Long userId, Long teamId, String teamName);

    void editUserNickName(Long userId, String userNick);

    List<Long> getUserIdsByUnitId(Long unitId);

    Map<Long, List<Long>> getUserIdsByUnitIds(List<Long> unitIds);

    void updateAcrossConfig(SpaceAcrossConfigDto dto);

    void batchUpdateAcrossConfig(List<SpaceAcrossConfigDto> dtoList);

    List<SpaceAcrossConfigDto> batchQueryAcrossConfig(List<String> spaceIdList);

    /**
     * 向空间站管理员发送 knock/mm 消息（空间站成员申请通知）
     */
    void sendWorkspaceApplyNotify(List<Long> adminUserIds, String message);

    // ========== Notification gRPC for collabspace ==========

    /**
     * 在 apitable 创建通知（通用，供审批流程调用）.
     */
    void createNotification(String templateId, String fromUserId, List<String> toUserIds,
                           String nodeId, String spaceId, String notifyBody, boolean sendKnockNotification);

    /**
     * 在 apitable 查询通知 body extras（审批时通过 notificationId 反查 requestId）.
     * @return Map with keys: requestId, spaceId, templateId
     */
    Map<String, String> getNotificationExtras(Long notificationId, Long toUserId);

    /**
     * 更新 apitable 通知的 body extras（如审批后写入 status、approver 信息）.
     */
    void updateNotificationExtras(Long notificationId, String status, String approverUserId, String approverNickName);

    /**
     * 标记 apitable 通知已读/未读.
     */
    void setNotificationRead(Long notificationId, Long toUserId, boolean isRead);
}

