package com.yottastudios.ns.collabspace.consumer.handle;

import cn.hutool.json.JSONUtil;
import com.alibaba.excel.util.StringUtils;
import com.yottastudios.ns.collabspace.grpc.IApitableGrpcClientService;
import com.yottastudios.ns.collabspace.interfaces.eventbus.model.UserSpaceChangeEvent;
import com.yottastudios.ns.collabspace.space.action.UserSpaceMemberSyncable;
import com.yottastudios.ns.collabspace.space.action.context.UserSpaceMemberSyncContext;
import com.yottastudios.ns.collabspace.space.action.factory.SpaceAppActionFactory;
import com.yottastudios.ns.collabspace.space.entity.SpaceAppRelEntity;
import com.yottastudios.ns.collabspace.space.enums.SpaceAppTypeEnum;
import com.yottastudios.ns.collabspace.space.service.ISpaceAppRelService;
import com.yottastudios.ns.collabspace.user.vo.UserSimpleInfoVo;
import com.yottastudios.ns.collabspace.workspace.permission.manager.PermissionCacheManager;
import jakarta.annotation.Resource;
import lombok.extern.slf4j.Slf4j;
import org.apache.commons.collections4.CollectionUtils;
import org.springframework.stereotype.Component;
import com.yottastudios.ns.collabspace.space.service.ISpaceService;
import com.yottastudios.ns.collabspace.space.entity.SpaceEntity;

import java.util.List;
import java.util.stream.Collectors;

@Component
@Slf4j
public class UserSpaceChangeEventHandler {

    @Resource
    private IApitableGrpcClientService apitableGrpcClientService;
    @Resource
    private ISpaceAppRelService spaceAppRelService;
    @Resource
    private ISpaceService spaceService;
    @Resource
    private SpaceAppActionFactory spaceAppActionFactory;
    @Resource
    private PermissionCacheManager permissionCacheManager;

    public void handle(UserSpaceChangeEvent event) {
        if (CollectionUtils.isEmpty(event.getUsers())) {
            log.warn("no user in UserSpaceChangeEvent");
            return;
        }

        String spaceId = event.getSpaceId();
        if (StringUtils.isBlank(spaceId)) {
            log.info("操作无SpaceId信息:{}", JSONUtil.toJsonStr(event));
            return;
        }

        if (event.getJoin()) {
            handleUserJoinSpace(event);
        } else {
            handleUserQuitSpace(event);
        }
    }

    private void handleUserJoinSpace(UserSpaceChangeEvent event) {
        SpaceEntity mainSpace = waitSpaceBySpaceId(event.getSpaceId());
        if (mainSpace == null) {
            log.info("主Space未就绪或不存在:{}", JSONUtil.toJsonStr(event));
            return;
        }
        // 三方应用用主管理员id, 防止出现鉴权问题
        Long operatorId = mainSpace.getOwner();
        UserSimpleInfoVo operatorInfo = apitableGrpcClientService.getUserById(operatorId);
        if (operatorInfo == null || StringUtils.isBlank(operatorInfo.getEmail())) {
            log.warn("操作者信息不完整, operatorId: {}", operatorId);
            return;
        }

        List<SpaceAppRelEntity> appRels = spaceAppRelService.listBySpaceId(event.getSpaceId());
        if (CollectionUtils.isEmpty(appRels)) {
            return;
        }

        permissionCacheManager.updateAllNodesCacheAndBroadcast(mainSpace.getSpaceId(), operatorInfo.getId());

        List<UserSpaceMemberSyncContext.UserInfo> users = event.getUsers().stream()
                .map(u -> new UserSpaceMemberSyncContext.UserInfo(u.getUserId(), u.getEmail()))
                .collect(Collectors.toList());

        for (SpaceAppRelEntity appRel : appRels) {
            SpaceAppTypeEnum appType = SpaceAppTypeEnum.fromValue(appRel.getAppType());
            if (appType == null) {
                continue;
            }

            UserSpaceMemberSyncable syncable = spaceAppActionFactory.getUserSpaceMemberSyncable(appType);
            if (syncable == null) {
                continue;
            }

            UserSpaceMemberSyncContext ctx = UserSpaceMemberSyncContext.builder()
                    .spaceId(event.getSpaceId())
                    .appSpaceId(appRel.getAppSpaceId())
                    .operatorId(operatorId)
                    .operatorEmail(operatorInfo.getEmail())
                    .users(users)
                    .build();

            syncable.syncMemberJoin(ctx);
        }
    }

    private void handleUserQuitSpace(UserSpaceChangeEvent event) {
        SpaceEntity mainSpace = waitSpaceBySpaceId(event.getSpaceId());
        if (mainSpace == null) {
            log.info("主Space未就绪或不存在:{}", JSONUtil.toJsonStr(event));
            return;
        }
        // 三方应用用主管理员id, 防止出现鉴权问题
        Long operatorId = mainSpace.getOwner();
        UserSimpleInfoVo operatorInfo = apitableGrpcClientService.getUserById(operatorId);
        if (operatorInfo == null || StringUtils.isBlank(operatorInfo.getEmail())) {
            log.warn("操作者信息不完整, operatorId: {}", operatorId);
            return;
        }

        List<SpaceAppRelEntity> appRels = spaceAppRelService.listBySpaceId(event.getSpaceId());
        if (CollectionUtils.isEmpty(appRels)) {
            return;
        }

        List<UserSpaceMemberSyncContext.UserInfo> users = event.getUsers().stream()
                .map(u -> new UserSpaceMemberSyncContext.UserInfo(u.getUserId(), u.getEmail()))
                .collect(Collectors.toList());

        for (SpaceAppRelEntity appRel : appRels) {
            SpaceAppTypeEnum appType = SpaceAppTypeEnum.fromValue(appRel.getAppType());
            if (appType == null) {
                continue;
            }

            UserSpaceMemberSyncable syncable = spaceAppActionFactory.getUserSpaceMemberSyncable(appType);
            if (syncable == null) {
                continue;
            }

            UserSpaceMemberSyncContext ctx = UserSpaceMemberSyncContext.builder()
                    .spaceId(event.getSpaceId())
                    .appSpaceId(appRel.getAppSpaceId())
                    .operatorId(operatorId)
                    .operatorEmail(operatorInfo.getEmail())
                    .users(users)
                    .build();

            syncable.syncMemberQuit(ctx);
        }
    }

    // 因迁移时space插入的事务可能尚未提交，这里增加查询等待，迁完可以去掉
    private SpaceEntity waitSpaceBySpaceId(String spaceId) {
        int maxAttempts = 3;
        for (int attempt = 0; attempt < maxAttempts; attempt++) {
            SpaceEntity entity = spaceService.getBySpaceId(spaceId);
            if (entity != null) return entity;
            long sleepSeconds = 1L << attempt; // 1,2,4
            try {
                Thread.sleep(sleepSeconds * 1000);
            } catch (InterruptedException e) {
                Thread.currentThread().interrupt();
                break;
            }
        }
        return null;
    }
}

