    String affineSpaceId = saveAppRel(remoteSpace, mainAdminUserId);

    try {
        Thread.sleep(5000);
    } catch (InterruptedException e) {
        throw new RuntimeException(e);
    }

    // 同步该space所有member到上面新建的affine workspace
    syncMember(spaceId, mainAdminUserId, affineSpaceId, members);

    // 同步该space管理员信息到本应用和所有子应用
    syncAdmin(spaceId, mainAdminUserId);
    // 同步文件树结构
    List<SpaceNodeEntity> spaceNodes = syncFolderStruct(spaceId, mainAdminUserId);

    // 同步权限
    syncControls(spaceId, spaceNodes);

    // 同步收藏
    syncFavorites(spaceId, spaceNodes, members);

    return true;
}

private void syncMember(String spaceId, Long mainAdminUserId, String affineSpaceId, List<MemberEntity> members) {
    String adminEmail = members.stream()
        .filter(member -> mainAdminUserId.equals(member.getUserId()))
        .findFirst()
        .map(MemberEntity::getEmail)
        .orElse(null);

    if (adminEmail == null) {
        log.error("未找到主管理员邮箱: spaceId={}, mainAdminUserId={}", spaceId, mainAdminUserId);
        return;
    }

    List<String> emails = members.stream()
        .map(MemberEntity::getEmail)
        .filter(email -> email != null && !email.equals(adminEmail))
        .toList();

    log.info("同步affine成员: spaceId={}, adminEmail={}, memberCount={}, affineSpaceId = {}", spaceId, adminEmail, emails.size(), affineSpaceId);

    for (String email : emails) {
        SetPermissionRequest request = new SetPermissionRequest(affineSpaceId, email, AffineWorkspaceAuthTypeEnum.MEMBER.getValue());
        affineHttpClientService.inviteUser(request, mainAdminUserId);
    }
}

private String saveAppRel(SpaceEntity remoteSpace, Long mainAdminUserId) {
    String affineSpaceId = affineHttpClientService.createWorkspace(CreateWorkspaceRequest.builder().spaceName(remoteSpace.getName()).resource("aio").build(),mainAdminUserId);
    spaceAppRelService.addRel(remoteSpace.getSpaceId(), SpaceAppTypeEnum.APITABLE.getValue(), remoteSpace.getSpaceId());
    spaceAppRelService.addRel(remoteSpace.getSpaceId(), SpaceAppTypeEnum.AFFINE.getValue(), affineSpaceId);
    return affineSpaceId;
}

private List<SpaceNodeEntity> syncFolderStruct(String spaceId, Long mainAdminUserId) {
    ApitableMigrationFeign.ResponseData<NodeInfoTreeVo> response = apitableMigrationFeign.getSpaceTree(spaceId);
    if (response == null || !Boolean.TRUE.equals(response.getSuccess()) || response.getData() == null) {
        log.error("getSpaceTree fail: {}-{}", response,spaceId);
        return new ArrayList<>();
    }
    NodeInfoTreeVo originTree = response.getData();

    // 对原始树的子节点按preNodeId进行排序
    if (CollectionUtils.isNotEmpty(originTree.getChildren())) {
        originTree.setChildren(sortNodesByPreId(originTree.getChildren()));
    }

    NodeInfoTreeVo apitableTree = filterAitableTree(originTree);
    NodeInfoTreeVo luckysheetTree = filterLuckysheetTree(originTree);
    NodeInfoTreeVo outlineTree = filterOutlineTreeTree(originTree);
    // apitable相关文件树直接存根节点下
    List<SpaceNodeEntity> allSpaceNodes = new ArrayList<>();

    if (CollectionUtils.isNotEmpty(apitableTree.getChildren())) {
        allSpaceNodes.addAll(saveTree(spaceId, DefaultTreeBuildFactory.ROOT_PARENT_ID, apitableTree.getChildren(), mainAdminUserId));
    }

