private List<TeamMemberVo> convertResultToVo(List<GetTeamBranchResult> teamList) {
    List<TeamMemberVo> resultList = new ArrayList<>();
    if (teamList == null || teamList.isEmpty()) {
        return resultList;
    }
    teamList.forEach(item -> {
        TeamMemberVo vo = new TeamMemberVo();
        vo.setMemberCount(item.getMemberCount());
        vo.setTeamId(item.getTeamId());
        vo.setParentTeamId(item.getParentId());
        vo.setTeamName(item.getTeamName());
        vo.setChildrenList(convertResultToVo(item.getChildrenList()));
        vo.setMemberList(new ArrayList<>());
        resultList.add(vo);
    });
    return resultList;
}

