    private List<Long> listUserIdsBySpaceId(String spaceId) {
        ApitableMigrationFeign.ResponseData<List<MemberEntity>> memberResp = apitableMigrationFeign.getSpaceMembers(spaceId);// todo 可以优化为grpc调用
        if (memberResp == null || !Boolean.TRUE.equals(memberResp.getSuccess()) || memberResp.getData() == null) {
