package com.yottastudios.ns.collabspace.space.task;

import com.baomidou.mybatisplus.core.conditions.query.QueryWrapper;
import com.yottastudios.ns.collabspace.shared.cache.service.UserCacheService;
import com.yottastudios.ns.collabspace.space.entity.SpaceEntity;
import com.yottastudios.ns.collabspace.space.manager.update.SpaceUpdateManager;
import com.yottastudios.ns.collabspace.space.service.ISpaceService;
import jakarta.annotation.Resource;
import lombok.extern.slf4j.Slf4j;
import org.springframework.boot.CommandLineRunner;
import org.springframework.boot.autoconfigure.condition.ConditionalOnProperty;
import org.springframework.core.annotation.Order;
import org.springframework.stereotype.Component;

import java.util.*;
import java.util.stream.Collectors;

/**
 * 批量更新线上空间站名称（历史数据修复）
 * 1. 删除非法字符：/ : * ? " < > |
 * 2. AF- 替换为主管理员名称
 * 3. 重名加自增序号
 * <p>
 * 启用：batch.space.name.enabled=true（启动时执行一次）
 */
@Slf4j
@Component
@Order()
@ConditionalOnProperty(name = "batch.space.name.enabled", havingValue = "true")
public class BatchSpaceNameUpdateTask implements CommandLineRunner {

    private static final String LOG_PREFIX = "[BatchSpaceNameUpdate] ";
    private static final String ILLEGAL_CHARS = "/:*?\"<>|";

    @Resource
    private ISpaceService spaceService;
    @Resource
    private SpaceUpdateManager spaceUpdateManager;
    @Resource
    private UserCacheService userCacheService;

    @Override
    public void run(String... args) {
        log.info("{}开始执行批量更新空间站名称任务", LOG_PREFIX);
        try {
            List<SpaceEntity> spaces = spaceService.list(
                    new QueryWrapper<SpaceEntity>().lambda()
                            .eq(SpaceEntity::getIsDeleted, 0)
                            .eq(SpaceEntity::getIsForbid, false));
            if (spaces.isEmpty()) {
                log.info("{}无待处理空间站", LOG_PREFIX);
                return;
            }

            // 1. 计算新名称（包括原本就合法的名称，这样后续重名处理也能覆盖到）
            List<SpaceRenameItem> items = spaces.stream()
                    .map(s -> new SpaceRenameItem(s, computeNewName(s)))
                    .toList();

            // 2. 解决重名（考虑全部空间站名称，避免与未修改的冲突）
            Set<String> existingNames = spaces.stream().map(SpaceEntity::getName).collect(Collectors.toSet());
            Map<String, String> spaceIdToFinalName = resolveDuplicates(items, existingNames);

            // 如果最终没有任何名称发生变化，则直接返回
            long changedCount = items.stream()
                    .filter(item -> {
                        String finalName = spaceIdToFinalName.get(item.space.getSpaceId());
                        return finalName != null && !Objects.equals(finalName, item.oldName);
                    })
                    .count();
            if (changedCount == 0) {
                log.info("{}无需要更新的空间站", LOG_PREFIX);
                return;
            }

            // 3. 执行更新，并打印恢复语句
            int success = 0, fail = 0;
            for (SpaceRenameItem item : items) {
                String finalName = spaceIdToFinalName.get(item.space.getSpaceId());
                if (finalName == null || Objects.equals(finalName, item.oldName)) continue;
                if (item.space.getOwner() == null) {
                    log.warn("{}owner为空, 跳过更新, spaceId={}", LOG_PREFIX, item.space.getSpaceId());
                    fail++;
                    continue;
                }
                try {
                    spaceUpdateManager.renameSpace(item.space.getOwner(), item.space.getSpaceId(), finalName);
                    success++;
                    String updateRecovery = buildUpdateRecoverySql(item.space.getSpaceId(), item.oldName);
                    log.info("{}更新成功: spaceId={}, {} -> {} | 恢复: {}", LOG_PREFIX, item.space.getSpaceId(), item.oldName, finalName, updateRecovery);
                } catch (Exception e) {
                    fail++;
                    log.error("{}更新失败: spaceId={}, error={}", LOG_PREFIX, item.space.getSpaceId(), e.getMessage(), e);
                }
            }

            log.info("{}批量更新完成: 成功={}, 失败={}", LOG_PREFIX, success, fail);
        } catch (Exception e) {
            log.error("{}批量更新空间站名称失败", LOG_PREFIX, e);
        }
    }

    private String computeNewName(SpaceEntity space) {
        String name = space.getName();
        if (name == null || name.isBlank()) {
            log.warn("{}空间站名称为空, 跳过, spaceId={}", LOG_PREFIX, space.getSpaceId());
            return space.getName(); // 返回原值, 不会被加入更新列表
        }
        // 1. 删除非法字符
        for (char c : ILLEGAL_CHARS.toCharArray()) {
            name = name.replace(String.valueOf(c), "");
        }
        name = name.trim().replaceAll("\\s+", " ");

        // 2. AF- 替换为主管理员名
        if (name.startsWith("AF-")) {
            if (space.getOwner() == null) {
                log.warn("{}AF-前缀但owner为空, 无法替换, spaceId={}, name={}", LOG_PREFIX, space.getSpaceId(), name);
            } else {
                String mainAdminName = userCacheService.getNicknameByUserId(space.getOwner());
                if (mainAdminName != null && !mainAdminName.isBlank()) {
                    name = mainAdminName + name.substring(2); // "AF-" -> mainAdminName
                } else {
                    log.warn("{}AF-前缀但主管理员昵称为空, 无法替换, spaceId={}, ownerId={}, name={}", LOG_PREFIX, space.getSpaceId(), space.getOwner(), name);
                }
            }
        }

        if (name.isBlank()) {
            log.warn("{}清理后名称为空, 保留原名, spaceId={}, oldName={}", LOG_PREFIX, space.getSpaceId(), space.getName());
            return space.getName();
        }
        return name;
    }

    private Map<String, String> resolveDuplicates(List<SpaceRenameItem> items, Set<String> existingNames) {
        Map<String, String> result = new HashMap<>();
        // 记录每个基础名称已经“分配”了多少次，用于决定谁保留原名、谁加序号
        Map<String, Integer> nameCount = new HashMap<>();
        // 所有已经占用的名称（包含历史的），用于避免与其它不同空间的名称冲突
        Set<String> usedNames = new HashSet<>(existingNames);

        for (SpaceRenameItem item : items) {
            String baseName = item.newName != null && !item.newName.isBlank() ? item.newName : "未命名";

            int index = nameCount.getOrDefault(baseName, 0);
            String finalName;

            if (index == 0) {
                // 第一条使用这个名称的空间站，保留基础名称本身
                finalName = baseName;
            } else {
                // 后续同名空间站，从 1 开始依次追加序号，并且跳过已经被占用的名字
                int suffix = index;
                finalName = baseName + " " + suffix;
                while (usedNames.contains(finalName)) {
                    suffix++;
                    finalName = baseName + " " + suffix;
                }
                index = suffix;
            }

            nameCount.put(baseName, index + 1);
            usedNames.add(finalName);
            result.put(item.space.getSpaceId(), finalName);
        }
        return result;
    }

    private static String buildUpdateRecoverySql(String spaceId, String oldName) {
        if (spaceId == null) return "-- spaceId为空, 跳过";
        String escaped = (oldName == null ? "" : oldName).replace("\\", "\\\\").replace("'", "''");
        return "UPDATE collabspace_space SET name = '" + escaped + "' WHERE space_id = '" + spaceId + "';";
    }

    private record SpaceRenameItem(SpaceEntity space, String oldName, String newName) {
        SpaceRenameItem(SpaceEntity space, String newName) {
            this(space, space.getName(), newName);
        }
    }
}

