package com.apitable.organization.task;

import com.baomidou.mybatisplus.core.conditions.query.LambdaQueryWrapper;
import com.baomidou.mybatisplus.core.conditions.update.LambdaUpdateWrapper;
import com.apitable.organization.entity.MemberEntity;
import com.apitable.organization.service.IMemberService;
import com.apitable.user.entity.UserEntity;
import com.apitable.user.service.IUserService;
import jakarta.annotation.Resource;
import lombok.extern.slf4j.Slf4j;
import org.springframework.boot.CommandLineRunner;
import org.springframework.boot.autoconfigure.condition.ConditionalOnProperty;
import org.springframework.core.annotation.Order;
import org.springframework.stereotype.Component;

import java.util.List;
import java.util.Map;
import java.util.regex.Pattern;
import java.util.stream.Collectors;

/**
 * 批量修复历史数据：将 member_name 为拼音的记录更新为用户的中文 nick_name
 * <p>
 * 原因：历史批量导入逻辑默认使用拼音作为 member_name，导致与 nick_name（中文）不一致，
 * 进而导致 collabspace 向 apitable 同步时按 memberName 匹配失败。
 * <p>
 * 启用：batch.member.name.fix.enabled=true（启动时执行一次）
 */
@Slf4j
@Component
@Order
@ConditionalOnProperty(name = "batch.member.name.fix.enabled", havingValue = "true")
public class BatchMemberNameFixTask implements CommandLineRunner {

    private static final String LOG_PREFIX = "[BatchMemberNameFix] ";

    /**
     * 匹配纯 ASCII 字符串（拼音/英文/数字/下划线等）
     */
    private static final Pattern ASCII_PATTERN = Pattern.compile("^[\\x00-\\x7F]+$");

    /**
     * 包含至少一个中文字符
     */
    private static final Pattern CHINESE_PATTERN = Pattern.compile("[\\u4e00-\\u9fa5]");

    @Resource
    private IUserService userService;

    @Resource
    private IMemberService memberService;

    @Override
    public void run(String... args) {
        log.info("{}开始执行批量修复成员花名任务", LOG_PREFIX);
        try {
            // 1. 查所有未删除用户，筛选 nick_name 含中文的
            List<UserEntity> users = userService.list(
                    new LambdaQueryWrapper<UserEntity>().eq(UserEntity::getIsDeleted, false));
            Map<Long, String> userNickMap = users.stream()
                    .filter(u -> u.getNickName() != null && CHINESE_PATTERN.matcher(u.getNickName()).find())
                    .collect(Collectors.toMap(UserEntity::getId, UserEntity::getNickName, (a, b) -> a));

            if (userNickMap.isEmpty()) {
                log.info("{}无中文 nick_name 的用户，跳过", LOG_PREFIX);
                return;
            }

            // 2. 查所有未删除的成员记录
            List<MemberEntity> members = memberService.list(
                    new LambdaQueryWrapper<MemberEntity>().eq(MemberEntity::getIsDeleted, false));

            // 3. 筛选需要修复的：nick_name 是中文，member_name 是纯 ASCII（拼音），且两者不同
            int success = 0;
            int skip = 0;
            for (MemberEntity member : members) {
                String nickName = userNickMap.get(member.getUserId());
                if (nickName == null) {
                    continue;
                }
                String memberName = member.getMemberName();
                if (memberName == null || nickName.equals(memberName)) {
                    continue;
                }
