        skip++;
        continue;
    }

    // 执行更新
    boolean updated = memberService.update(
            new LambdaUpdateWrapper<MemberEntity>()
                    .eq(MemberEntity::getId, member.getId())
                    .set(MemberEntity::getMemberName, nickName));
    if (updated) {
        success++;
        cacheToDelete.add(new long[]{member.getUserId(), member.getId()});
        String recoverySql = String.format(
                "UPDATE apitable_unit_member SET member_name = '%s' WHERE id = %d;",
                escapeSql(memberName), member.getId());
        log.info("{}修复成功: memberId={}, spaceId={}, userId={}, '{}' -> '{}' | 恢复: {}",
                LOG_PREFIX, member.getId(), member.getSpaceId(), member.getUserId(),
                memberName, nickName, recoverySql);
    }
}

// 4. 清除修复记录对应的 UserSpace 缓存，使 /user/me 等接口立即返回新值
int cacheCleared = 0;
for (MemberEntity member : members) {
    String nickName = userNickMap.get(member.getUserId());
    if (nickName == null || member.getMemberName() == null || !nickName.equals(member.getMemberName())) {
        // 只清已更新成功的（此时内存中的 member 对象还是旧值，需要用 cacheToDelete 判断）
        continue;
    }
}
for (long[] pair : cacheToDelete) {
    // pair 存的是 userId，需要通过 members 找 spaceId
}
// 用更简洁的方式：遍历修复过的成员，按 userId+spaceId 清缓存
Map<Long, List<String>> userSpaceMap = members.stream()
        .filter(m -> userNickMap.containsKey(m.getUserId())
                && m.getMemberName() != null
                && ASCII_PATTERN.matcher(m.getMemberName()).matches()
                && !userNickMap.get(m.getUserId()).equals(m.getMemberName()))
        .collect(Collectors.groupingBy(MemberEntity::getUserId,
                Collectors.mapping(MemberEntity::getSpaceId, Collectors.toList())));
for (var entry : userSpaceMap.entrySet()) {
    for (String spaceId : entry.getValue()) {
        try {
            userSpaceCacheService.delete(entry.getKey(), spaceId);
            cacheCleared++;
        } catch (Exception e) {
            log.warn("{}清除缓存失败: userId={}, spaceId={}", LOG_PREFIX, entry.getKey(), spaceId, e);
        }
    }
}

log.info("{}批量修复完成: 修复={}, 跳过(member_name非ASCII)={}, 缓存清除={}", LOG_PREFIX, success, skip, cacheCleared);

